import{_ as t,o as a,c as d,a2 as n}from"./chunks/framework.DnrXFDHb.js";const b=JSON.parse('{"title":"Random Image API en openbare gallery","description":"","frontmatter":{},"headers":[],"relativePath":"nl-NL/Other/random-image-api-and-public-gallery.md","filePath":"nl-NL/Other/random-image-api-and-public-gallery.md","lastUpdated":1781962217000}'),o={name:"nl-NL/Other/random-image-api-and-public-gallery.md"};function r(i,e,l,s,p,g){return a(),d("div",null,[...e[0]||(e[0]=[n(`<h1 id="random-image-api-en-openbare-gallery" tabindex="-1">Random Image API en openbare gallery <a class="header-anchor" href="#random-image-api-en-openbare-gallery" aria-label="Permalink to &quot;Random Image API en openbare gallery&quot;">​</a></h1><p>Beide functies configureer je onder:</p><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>System Settings -&gt; Other Settings</span></span></code></pre></div><h2 id="random-image-api" tabindex="-1">Random Image API <a class="header-anchor" href="#random-image-api" aria-label="Permalink to &quot;Random Image API&quot;">​</a></h2><p>De Random Image API geeft één willekeurig bestand terug uit geselecteerde mappen. Dit is handig voor siteachtergronden, avatarrotatie of willekeurige afbeeldingsaanroepen vanaf externe pagina&#39;s.</p><p>Na inschakelen gebruik je:</p><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>https://your-domain.com/random</span></span></code></pre></div><h2 id="instellingen-voor-random-image-api" tabindex="-1">Instellingen voor Random Image API <a class="header-anchor" href="#instellingen-voor-random-image-api" aria-label="Permalink to &quot;Instellingen voor Random Image API&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Optie</th><th>Doel</th></tr></thead><tbody><tr><td>Enable</td><td>Zet de <code>/random</code>-endpoint aan of uit. Als dit uit staat, is toegang verboden.</td></tr><tr><td>Directories</td><td>Beperkt welke mappen de random API mag gebruiken. Mappen die hier niet staan, kunnen niet door de API worden gebruikt.</td></tr><tr><td>Call demo</td><td>Genereert random API-links die je direct kunt kopiëren.</td></tr></tbody></table><p>Je kunt meerdere mappen selecteren. Als bijvoorbeeld alleen <code>/landscape/</code> en <code>/portrait/</code> zijn toegestaan, kan de random API alleen bestanden uit die mappen en hun submappen kiezen.</p><h2 id="parameters-van-random-image-api" tabindex="-1">Parameters van Random Image API <a class="header-anchor" href="#parameters-van-random-image-api" aria-label="Permalink to &quot;Parameters van Random Image API&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Parameter</th><th>Voorbeeld</th><th>Doel</th></tr></thead><tbody><tr><td><code>dir</code></td><td><code>/landscape/</code></td><td>Geeft de random map aan.</td></tr><tr><td><code>content</code></td><td><code>image</code></td><td>Geeft mediatype aan. Gebruik <code>image</code>, <code>video</code>, <code>audio</code> of combinaties met komma&#39;s.</td></tr><tr><td><code>orientation</code></td><td><code>auto</code></td><td>Filtert afbeeldingsoriëntatie. Gebruik <code>portrait</code>, <code>landscape</code> of <code>auto</code>.</td></tr><tr><td><code>type</code></td><td><code>url</code></td><td>Teruggeefformaat. Leeg betekent redirect, <code>url</code> geeft een tekst-URL terug, <code>json</code> geeft JSON terug.</td></tr><tr><td><code>origin</code></td><td><code>1</code></td><td>Gebruikt met <code>type=url</code> om een volledige URL terug te geven.</td></tr><tr><td><code>age</code></td><td><code>all-ages,r12</code></td><td>Filtert op leeftijdsrating.</td></tr><tr><td><code>tag</code></td><td><code>wallpaper,sky</code></td><td>Geeft alleen bestanden terug met deze tags.</td></tr><tr><td><code>ex</code></td><td><code>private</code></td><td>Sluit bestanden met deze tags uit.</td></tr></tbody></table><h2 id="teruggeefformaten" tabindex="-1">Teruggeefformaten <a class="header-anchor" href="#teruggeefformaten" aria-label="Permalink to &quot;Teruggeefformaten&quot;">​</a></h2><p>Zonder <code>type</code> redirect de API direct naar de willekeurige bestands-URL.</p><p>Met <code>type=url</code> geeft hij een tekst-URL terug.</p><p>Met <code>type=json</code> geeft hij bestandsinformatie terug, zoals bestands-URL, bestands-ID, naam, type, tags, rating en metadata.</p><h2 id="toegangsregels" tabindex="-1">Toegangsregels <a class="header-anchor" href="#toegangsregels" aria-label="Permalink to &quot;Toegangsregels&quot;">​</a></h2><p>De Random Image API volgt de openbare toegangsregels:</p><table tabindex="0"><thead><tr><th>Regel</th><th>Effect</th></tr></thead><tbody><tr><td>Mapbeperking</td><td>Alleen bestanden in toegestane mappen kunnen worden geselecteerd.</td></tr><tr><td>Blocklist</td><td>Bestanden op de blocklist worden uitgesloten van de random pool.</td></tr><tr><td>Allowlist-modus</td><td>Wanneer ingeschakeld, worden alleen bestanden teruggegeven die openbaar zijn toegestaan.</td></tr><tr><td>Leeftijdsrating</td><td>R12, R16, R18 en vergelijkbare inhoud wordt gefilterd volgens de huidige toegangsmodus.</td></tr></tbody></table><p>Als na filtering geen bestand overblijft, geeft de API geen passend resultaat terug.</p><h2 id="cache" tabindex="-1">Cache <a class="header-anchor" href="#cache" aria-label="Permalink to &quot;Cache&quot;">​</a></h2><p>De Random Image API cachet kandidaatpools per map om sneller te werken.</p><p>Wanneer bestanden veranderen, werkt ImgBed de cacheversie van de map bij. Latere verzoeken bouwen de kandidaatpool opnieuw op. Lege mappen worden kort gecachet om herhaalde queries te voorkomen.</p><h2 id="openbare-gallery" tabindex="-1">Openbare gallery <a class="header-anchor" href="#openbare-gallery" aria-label="Permalink to &quot;Openbare gallery&quot;">​</a></h2><p>De openbare gallery biedt een alleen-lezen pagina voor mappen die bezoekers mogen bekijken.</p><p>Na inschakelen kunnen bezoekers openen:</p><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>https://your-domain.com/browse/directory-name</span></span></code></pre></div><h2 id="instellingen-voor-openbare-gallery" tabindex="-1">Instellingen voor openbare gallery <a class="header-anchor" href="#instellingen-voor-openbare-gallery" aria-label="Permalink to &quot;Instellingen voor openbare gallery&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Optie</th><th>Doel</th></tr></thead><tbody><tr><td>Enable</td><td>Zet de openbare gallery aan of uit. Als dit uit staat, kunnen bezoekers niet bladeren.</td></tr><tr><td>Image loading mode</td><td>Bepaalt of previews originele afbeeldingen of thumbnails gebruiken.</td></tr><tr><td>Open directories</td><td>Bepaalt welke mappen bezoekers mogen openen.</td></tr></tbody></table><h2 id="afbeeldingslaadmodus" tabindex="-1">Afbeeldingslaadmodus <a class="header-anchor" href="#afbeeldingslaadmodus" aria-label="Permalink to &quot;Afbeeldingslaadmodus&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Modus</th><th>Doel</th></tr></thead><tbody><tr><td>Original</td><td>De bezoekerspagina laadt originele bestanden direct.</td></tr><tr><td>Thumbnail</td><td>De bezoekerspagina gebruikt bij voorkeur thumbnails voor sneller laden.</td></tr></tbody></table><h2 id="open-mappen" tabindex="-1">Open mappen <a class="header-anchor" href="#open-mappen" aria-label="Permalink to &quot;Open mappen&quot;">​</a></h2><p>Open mappen bepalen wat bezoekers kunnen zien.</p><p>Bijvoorbeeld:</p><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>/1/,/2/,/landscape/,/portrait/</span></span></code></pre></div><p>Bezoekers kunnen dan openen:</p><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>https://your-domain.com/browse/1</span></span>
<span class="line"><span>https://your-domain.com/browse/2</span></span>
<span class="line"><span>https://your-domain.com/browse/landscape</span></span>
<span class="line"><span>https://your-domain.com/browse/portrait</span></span></code></pre></div><p>Submappen kunnen ook worden geopend, zoals <code>/2026/lucky/</code>. Bezoekers worden geblokkeerd voor mappen die niet open zijn.</p><h2 id="functies-van-de-openbare-gallery" tabindex="-1">Functies van de openbare gallery <a class="header-anchor" href="#functies-van-de-openbare-gallery" aria-label="Permalink to &quot;Functies van de openbare gallery&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Functie</th><th>Beschrijving</th></tr></thead><tbody><tr><td>Door mappen bladeren</td><td>Bekijk bestanden en submappen in open mappen.</td></tr><tr><td>Zoeken</td><td>Zoek op bestandsnaam, bestands-ID of tags.</td></tr><tr><td>Typefilter</td><td>Filter afbeeldingen, video&#39;s, audio of andere bestanden.</td></tr><tr><td>Tagfilter</td><td>Neem geselecteerde tags op of sluit ze uit.</td></tr><tr><td>Oriëntatiefilter</td><td>Filter liggende of staande afbeeldingen.</td></tr><tr><td>Tijdfilter</td><td>Filter op uploadperiode.</td></tr><tr><td>Extensiefilter</td><td>Filter op bestandsextensie.</td></tr><tr><td>Link kopiëren</td><td>Kopieer toeganglinks van bestanden.</td></tr><tr><td>Mediapreview</td><td>Bekijk of speel afbeeldingen, video en audio af op de bezoekerspagina.</td></tr></tbody></table><h2 id="toegangsregels-voor-de-openbare-gallery" tabindex="-1">Toegangsregels voor de openbare gallery <a class="header-anchor" href="#toegangsregels-voor-de-openbare-gallery" aria-label="Permalink to &quot;Toegangsregels voor de openbare gallery&quot;">​</a></h2><p>Ook de openbare gallery volgt openbare toegangsregels:</p><table tabindex="0"><thead><tr><th>Regel</th><th>Effect</th></tr></thead><tbody><tr><td>Open mappen</td><td>Alleen toegestane mappen worden getoond.</td></tr><tr><td>Access mode</td><td>Inhoud wordt gefilterd volgens de huidige leeftijdsclassificatiemodus.</td></tr><tr><td>Allowlist-modus</td><td>Wanneer ingeschakeld, worden alleen bestanden getoond die openbaar zijn toegestaan.</td></tr><tr><td>Blocklist</td><td>Bestanden op de blocklist worden verborgen.</td></tr></tbody></table>`,43)])])}const h=t(o,[["render",r]]);export{b as __pageData,h as default};
